// pfConfAddition is appended to /etc/pf.conf to register the anchor.
// Leading newline provides a blank-line separator from existing content.
const pfConfAddition = `
# Claude Code hazmat user blocklist
anchor "agent"
load anchor "agent" from "/etc/pf.anchors/agent"
`

